mapper.select:
SELECT
, A.SICISOFFICESNAME , A.SOFFICENAME , A.SSVC_USE_TYPE_NM , A.SEX_SVC_NM , A.RNUM FROM ( SELECT
, A.SICISOFFICESNAME , A.SOFFICENAME , A.SSVC_USE_TYPE_NM , A.SEX_SVC_NM , ROWNUM RNUM FROM ( SELECT
FROM BIF.TB_IP_ALLOC_ORDER_MST A
AND A.BFLAG_STATUS = 'R'
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE A.RNUM >= #{firstIndex}

SELECT NIPMS_SVC_SEQ
, SEX_SVC_CD
FROM MST.TB_IPMS_SVC_MST
WHERE SUSE_TYPE_CD = 'CY0001'

	AND SEX_SVC_CD = #{sexSvcCd, jdbcType=VARCHAR}


	AND SSVC_USE_TYPE_CD = #{ssvcUseTypeCd, jdbcType=CHAR}


	AND SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}

limit 1

SELECT	SASSIGN_TYPE_CD	as code
	,	SASSIGN_TYPE_NM	as name
FROM	MST.TB_ASSIGN_TYPE_CD
WHERE SASSIGN_TYPE_CD IN 
(SELECT SASSIGN_TYPE_CD FROM MST.TB_IPMS_SVC_MST
WHERE SUSE_TYPE_CD = 'CY0001'

	AND SEX_SVC_CD = #{sexSvcCd, jdbcType=VARCHAR}


	AND SSVC_USE_TYPE_CD = #{ssvcUseTypeCd, jdbcType=CHAR}

)
ORDER BY SASSIGN_TYPE_CD

SELECT A.SOFFICECODE AS code , B.SLVL_NM as name FROM BIF.TB_IP_ALLOC_ORDER_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SOFFICECODE = B.SLVL_CD AND A.SICISOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)) GROUP BY A.SOFFICECODE, B.SLVL_NM ORDER BY B.SLVL_NM

SELECT A.SOFFICECODE , B.SLVL_NM AS SOFFICENAME FROM BIF.TB_IP_ALLOC_ORDER_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SOFFICECODE = B.SLVL_CD AND A.SICISOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)) GROUP BY A.SOFFICECODE, B.SLVL_NM ORDER BY B.SLVL_NM
